import { CardActivity, Box, Button } from '@semparar/design-system-app';
import { PropsCardActivity } from '@semparar/design-system-app/src/atomic/molecules/CardActivity/Models';
import { capitalizeFirstLetters } from '@semparar/mf-app-fintech-onboarding/src/utils/formaters';
import React, { FC, useMemo } from 'react';

import { BenefitListProps } from './Models';
import { FlatList } from './styles';

type PropsCardActivityExtended = PropsCardActivity & {
  priority: number;
};

export const BenefitList: FC<BenefitListProps> = ({ benefits, itemOnPress, onBackButtonPress }) => {
  const benefitList = useMemo<PropsCardActivityExtended[]>(
    () =>
      Object.entries(benefits ?? {})
        ?.filter(([_, { idTitle, idText, idFullTitle, idFullText, idIcone, idType }]) => {
          return (
            !!idTitle?.text &&
            !!idText?.text &&
            !!idFullTitle?.text &&
            !!idFullText?.text &&
            !!idIcone?.text &&
            !!idType?.text
          );
        })
        ?.map(
          ([_, value]) =>
            ({
              onPress: () => {
                itemOnPress(value);
              },
              showIcon: true,
              hideBorder: true,
              title: value.idTitle?.text,
              description: value.idText?.text,
              icon: value.idIcone?.text,
              priority: Number(value.idPriority?.text) || 0,
              showTagLabel: !!value?.idTagCard?.text,
              textTagLabel: capitalizeFirstLetters(value?.idTagCard?.text),
              typeTagLabel: 'neutral',
              highlightTagLabel: !!value?.idTagCard?.text,
            } as PropsCardActivityExtended)
        )
        .sort((a, b) => (a.priority ?? 0) - (b.priority ?? 0)),
    [benefits, itemOnPress]
  );

  return (
    <FlatList
      data={benefitList}
      keyExtractor={(item) => item.priority.toString()}
      renderItem={({ item }) => {
        return <CardActivity {...item} />;
      }}
    />
  );
};

